import heapq

def minPath(grid, k):
    N = len(grid)
    min_heap = []
    for i in range(N):
        for j in range(N):
            heapq.heappush(min_heap, (grid[i][j], i, j))

    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    min_path = [float('inf')] * k
    visited = [[False] * N for _ in range(N)]

    def dfs(x, y, path):
        nonlocal min_path
        if len(path) == k:
            if path < min_path:
                min_path = path[:]
            return
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < N and 0 <= ny < N and not visited[nx][ny]:
                visited[nx][ny] = True
                path.append(grid[nx][ny])
                dfs(nx, ny, path)
                path.pop()
                visited[nx][ny] = False

    while min_heap:
        val, x, y = heapq.heappop(min_heap)
        if val > min_path[0]:
            break
        visited[x][y] = True
        dfs(x, y, [val])
        visited[x][y] = False

    return min_path

